                      <button onClick={()=>sp("contact")} style={{background:"transparent",color:"#1a1210",border:"1px solid #ccc",padding:"13px 26px",fontFamily:"'Plus Jakarta Sans',sans-serif",fontSize:11,letterSpacing:".08em",textTransform:"uppercase",cursor:"pointer",transition:"all .2s"}} onMouseEnter={e=>{e.currentTarget.style.borderColor="#c9a84c";e.currentTarget.style.color="#c85a0a";}} onMouseLeave={e=>{e.currentTarget.style.borderColor="#ccc";e.currentTarget.style.color="#1a1210";}}>Contact Team</button>
